// Extract model IDs for processing
const models = $input.first()?.json?.data || $input.first()?.json || [];

return models.map(m => ({
  json: {
    model_id: m.id,
    model_name: m.name,
    checkpoint: m.checkpoint,
    family: m.family,
    anomaly_detection_enabled: m.metadata?.anomaly_detection_enabled ?? true,
    alert_thresholds: m.metadata?.alert_thresholds || {
      ttsft_std_dev: 2.0,
      tps_drop_percent: 20,
      memory_increase_percent: 15
    }
  }
}));

// Calculate statistics and detect anomalies using z-score method
const ttsftData = $node["Fetch TTFT Trends"].json?.data || [];
const tpsData = $node["Fetch TPS Trends"].json?.data || [];
const memoryData = $node["Fetch Memory Trends"].json?.data || [];

const thresholds = $input.first().json.alert_thresholds;

function calculateStats(values) {
  if (values.length < 3) return null;

  const n = values.length;
  const mean = values.reduce((a, b) => a + b, 0) / n;
  const variance = values.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / n;
  const stdDev = Math.sqrt(variance);

  return { mean, stdDev, min: Math.min(...values), max: Math.max(...values) };
}

function detectAnomalies(data, metricName, thresholdStdDev) {
  const values = data.map(d => d.value).filter(v => v !== null && v !== undefined);
  if (values.length < 3) return [];

  const stats = calculateStats(values);
  if (!stats || stats.stdDev === 0) return [];

  const anomalies = [];
  const latestValue = values[values.length - 1];
  const zScore = Math.abs((latestValue - stats.mean) / stats.stdDev);

  if (zScore > thresholdStdDev) {
    anomalies.push({
      metric: metricName,
      latest_value: latestValue,
      mean: stats.mean,
      std_dev: stats.stdDev,
      z_score: zScore,
      deviation_percent: ((latestValue - stats.mean) / stats.mean) * 100,
      severity: zScore > 3 ? 'critical' : zScore > 2.5 ? 'high' : 'medium',
      detected_at: new Date().toISOString()
    });
  }

  // Check for trend degradation (last 5 values vs previous 5)
  if (values.length >= 10) {
    const recent = values.slice(-5);
    const previous = values.slice(-10, -5);
    const recentAvg = recent.reduce((a, b) => a + b, 0) / 5;
    const previousAvg = previous.reduce((a, b) => a + b, 0) / 5;
    const changePercent = ((recentAvg - previousAvg) / previousAvg) * 100;

    // For TTFT, increase is bad; for TPS, decrease is bad
    const isDegradation = metricName === 'seconds_to_first_token' 
      ? changePercent > 10 
      : changePercent < -10;

    if (isDegradation && Math.abs(changePercent) > 10) {
      anomalies.push({
        metric: metricName,
        trend_degradation: true,
        change_percent: changePercent,
        recent_avg: recentAvg,
        previous_avg: previousAvg,
        severity: Math.abs(changePercent) > 20 ? 'critical' : 'high',
        detected_at: new Date().toISOString()
      });
    }
  }

  return anomalies;
}

const allAnomalies = [
  ...detectAnomalies(ttsftData, 'seconds_to_first_token', thresholds.ttsft_std_dev || 2.0),
  ...detectAnomalies(tpsData, 'token_generation_tokens_per_second', 2.0),
  ...detectAnomalies(memoryData, 'max_memory_used_gbyte', thresholds.memory_increase_percent ? thresholds.memory_increase_percent / 10 : 1.5)
];

return {
  json: {
    model_id: $input.first().json.model_id,
    model_name: $input.first().json.model_name,
    checkpoint: $input.first().json.checkpoint,
    anomalies: allAnomalies,
    anomaly_count: allAnomalies.length,
    has_critical: allAnomalies.some(a => a.severity === 'critical'),
    analyzed_at: new Date().toISOString()
  }
};

