={
  "text": "🚨 Anomaly Detected: {{ $json.model_name }}",
  "blocks": [
    {
      "type": "header",
      "text": {
        "type": "plain_text",
        "text": "🚨 Performance Anomaly Detected"
      }
    },
    {
      "type": "section",
      "fields": [
        {
          "type": "mrkdwn",
          "text": "*Model:*\n{{ $json.model_name }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Checkpoint:*\n{{ $json.checkpoint }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Anomalies Found:*\n{{ $json.anomaly_count }}"
        },
        {
          "type": "mrkdwn",
          "text": "*Severity:*\n{{ $json.has_critical ? '🔴 CRITICAL' : '🟠 HIGH' }}"
        }
      ]
    },
    {{#each $json.anomalies}}
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "*{{ this.metric }}:*\nZ-Score: {{ this.z_score }} | Deviation: {{ Math.round(this.deviation_percent) }}%"
      }
    },
    {{/each}}
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": "<{{ $env.DASHBOARD_FRONTEND_URL || 'http://localhost:3000' }}/models/{{ $json.model_id }}/trends|View Trend Analysis>"
      }
    }
  ]
}

={
  "@type": "MessageCard",
  "@context": "http://schema.org/extensions",
  "themeColor": "{{ $json.has_critical ? 'FF0000' : 'FFA500' }}",
  "summary": "Performance Anomaly: {{ $json.model_name }}",
  "sections": [
    {
      "activityTitle": "🚨 Performance Anomaly Detected",
      "activitySubtitle": "Lemonade Eval Dashboard",
      "facts": [
        { "name": "Model", "value": "{{ $json.model_name }}" },
        { "name": "Checkpoint", "value": "{{ $json.checkpoint }}" },
        { "name": "Anomalies", "value": "{{ $json.anomaly_count }}" },
        { "name": "Severity", "value": "{{ $json.has_critical ? 'CRITICAL' : 'HIGH' }}" }
      ],
      "text": "{{ $json.anomalies.map(a => `${a.metric}: Z-Score ${a.z_score.toFixed(2)}, Deviation ${Math.round(a.deviation_percent)}%`).join('\n') }}",
      "potentialAction": [
        {
          "@type": "OpenUri",
          "name": "View Trends",
          "targets": [{ "os": "default", "uri": "{{ $env.DASHBOARD_FRONTEND_URL || 'http://localhost:3000' }}/models/{{ $json.model_id }}/trends" }]
        }
      ]
    }
  ]
}

